export async function loadExternalRemoveInteraction(engine) {
    engine.checkVersion("4.1.3");
    await engine.pluginManager.register(async (e) => {
        const { ensureInteractivityPluginLoaded } = await import("@tsparticles/plugin-interactivity/lazy");
        ensureInteractivityPluginLoaded(e);
        e.pluginManager.addInteractor?.("externalRemove", async (container) => {
            const { Remover } = await import("./Remover.js");
            return new Remover(container);
        });
    });
}
export * from "./Options/Classes/Remove.js";
